var apiKey = getVar('gemini_api_key');
if (!apiKey) return JSON.stringify({error: "Gemini API key not configured. Set the 'gemini_api_key' variable."});

var model = args.model || 'veo-3.1-fast-generate-001';
var validModels = ['veo-3.1-generate-001', 'veo-3.1-fast-generate-001', 'veo-3.0-generate-001', 'veo-3.0-fast-generate-001', 'veo-2.0-generate-001'];
if (validModels.indexOf(model) === -1) {
  return JSON.stringify({error: 'Invalid model. Valid models: ' + validModels.join(', ') + '. Got: ' + model});
}

var duration = args.duration || 8;
var validDurations = [4, 6, 8];
if (validDurations.indexOf(duration) === -1) {
  duration = 8;
}
var aspectRatio = args.aspect_ratio || '9:16';
var generateAudio = args.generate_audio !== false;

var params = {
  aspectRatio: aspectRatio,
  durationSeconds: duration,
  personGeneration: 'allow_adult',
  sampleCount: 1
};
if (generateAudio && model.indexOf('veo-3') !== -1) {
  params.generateAudio = true;
}
if (args.negative_prompt) {
  params.negativePrompt = args.negative_prompt;
}
if (model.indexOf('veo-2') !== -1) {
  params.enhancePrompt = true;
}

var payload = JSON.stringify({
  instances: [{ prompt: args.prompt }],
  parameters: params
});

var baseUrl = 'https://generativelanguage.googleapis.com/v1beta';
var resp = httpPost(baseUrl + '/models/' + model + ':predictLongRunning?key=' + apiKey, payload, {
  'Content-Type': 'application/json'
});

if (resp.status !== 200) {
  var errBody = typeof resp.body === 'string' ? resp.body : JSON.stringify(resp.body);
  return JSON.stringify({error: 'Gemini API error (HTTP ' + resp.status + '): ' + errBody});
}

var opData = typeof resp.body === 'string' ? jsonParse(resp.body) : resp.body;
var opName = opData.name;
if (!opName) {
  return JSON.stringify({error: 'No operation name returned', response: opData});
}

for (var i = 0; i < 40; i++) {
  var waitResp = httpGet('https://httpstat.us/200?sleep=8000', {});

  var statusResp = httpGet(baseUrl + '/' + opName + '?key=' + apiKey, {});
  var statusData = typeof statusResp.body === 'string' ? jsonParse(statusResp.body) : statusResp.body;

  if (statusData.done === true) {
    if (statusData.error) {
      return JSON.stringify({error: 'Video generation failed', details: statusData.error}, null, 2);
    }
    var response = statusData.response;
    if (response && response.videos && response.videos.length > 0) {
      var video = response.videos[0];
      if (video.gcsUri) {
        return JSON.stringify({
          video_url: video.gcsUri,
          operation_name: opName,
          duration_seconds: duration,
          mime_type: video.mimeType || 'video/mp4'
        }, null, 2);
      }
      if (video.bytesBase64Encoded) {
        return JSON.stringify({
          video_base64: video.bytesBase64Encoded.substring(0, 100) + '...[truncated]',
          video_base64_full: video.bytesBase64Encoded,
          operation_name: opName,
          duration_seconds: duration,
          mime_type: video.mimeType || 'video/mp4',
          note: 'Video returned as base64. Use stitch_clips or save to file for further processing.'
        }, null, 2);
      }
    }
    return JSON.stringify({
      operation_name: opName,
      duration_seconds: duration,
      response: response,
      note: 'Video generated but output format unexpected. Check response field.'
    }, null, 2);
  }
}

return JSON.stringify({
  error: 'Video generation timed out after ~5 minutes',
  operation_name: opName,
  note: 'Use check_video_status to continue polling.'
}, null, 2);

