if (urlLower.indexOf('.png') !== -1) mimeType = 'image/png';

var imgBase64 = '';
if (typeof imgResp.body === 'string') {
  imgBase64 = btoa(imgResp.body);
} else {
  imgBase64 = btoa(JSON.stringify(imgResp.body));
}

var instance = {};
if (args.prompt) {
  instance.prompt = args.prompt;
}
instance.image = {
  bytesBase64Encoded: imgBase64,
  mimeType: mimeType
};

var params = {
  aspectRatio: aspectRatio,
  durationSeconds: duration,
  personGeneration: 'allow_adult',
  sampleCount: 1
};
if (generateAudio && model.indexOf('veo-3') !== -1) {
